class Solution:
    def leastOpsExpressTarget(self, x: int, target: int) -> int:
        import math
        def dfs(t):
            if t == 0:
                return 0
            if t < x:
                return min(2 * t - 1, 2 * (x - t))
            p = int(math.log(t, x))
            if x ** p == t:
                return p - 1
            diff = t - x ** p
            ans = dfs(diff) + p
            if x ** (p + 1) - t < t:
                ans = min(ans, dfs(x ** (p + 1) - t) + p + 1)
            return ans
        return dfs(target)
```
